<?php
namespace Database\Seeders; use App\Models\Inventory\{InventoryCategory,InventoryCondition,InventoryLocation,InventoryMeasurementUnit}; use Illuminate\Database\Seeder;
class InventoryMasterSeeder extends Seeder{public function run():void{foreach([['ELEK','Elektronik'],['MEJA_KURSI','Meja dan Kursi'],['KELAS','Peralatan Kelas'],['KANTOR','Peralatan Kantor'],['BUKU','Buku'],['BERSIH','Peralatan Kebersihan'],['OLAHRAGA','Peralatan Olahraga']] as $i=>$r)InventoryCategory::updateOrCreate(['code'=>$r[0]],['name'=>$r[1],'display_order'=>$i,'is_active'=>true]); foreach([['BAIK','Baik','normal'],['RUSAK_RINGAN','Rusak Ringan','warning'],['RUSAK_BERAT','Rusak Berat','danger'],['DALAM_PERBAIKAN','Dalam Perbaikan','warning'],['TIDAK_LAYAK','Tidak Layak Pakai','danger'],['HILANG','Hilang','danger']] as $i=>$r)InventoryCondition::updateOrCreate(['code'=>$r[0]],['name'=>$r[1],'severity'=>$r[2],'display_order'=>$i,'is_system'=>true,'is_active'=>true]); foreach(['unit','buah','set','paket','eksemplar','lusin','lembar','meter'] as $u)InventoryMeasurementUnit::updateOrCreate(['code'=>strtoupper($u)],['name'=>ucfirst($u),'is_active'=>true]); foreach([['RKM','Ruang Kepala Madrasah'],['RG','Ruang Guru'],['RK1','Ruang Kelas 1'],['RK2','Ruang Kelas 2'],['LAB','Laboratorium'],['PERPUS','Perpustakaan'],['GDG','Gudang'],['AULA','Aula']] as $r)InventoryLocation::updateOrCreate(['code'=>$r[0]],['name'=>$r[1],'type'=>'ruangan','is_active'=>true]);}}
